42	template <typename R, typename F, typename... As>
43	class QKernelHolder : public QKernelInterface<R, As...> {
44	public:
45	  using EntryType =
46	      std::conditional_t<std::is_class_v<F>, R (QKernelDummy::*)(As...),
47	                         R (*)(As...)>;
