49	  QKernelHolder() : entry{nullptr}, callable{} {}
50	  QKernelHolder(const QKernelHolder &) = default;
51	  QKernelHolder(QKernelHolder &&) = default;
52	
53	  explicit QKernelHolder(F &&f) : callable(std::forward<F>(f)) {
54	    if constexpr (std::is_same_v<F, R (*)(As...)>) {
55	      entry = f;
56	    } else {
57	      setEntry(&F::operator());
58	    }
59	  }
60	  explicit QKernelHolder(const F &f) : callable(f) {
61	    if constexpr (std::is_same_v<F, R (*)(As...)>) {
62	      entry = f;
63	    } else {
64	      setEntry(&F::operator());
65	    }
66	  }
67	
68	  QKernelHolder &operator=(const QKernelHolder &) = default;
69	  QKernelHolder &operator=(QKernelHolder &&holder) = default;
70	
71	  R dispatch(As... as) override { return std::invoke(callable, as...); }
72	
73	  // Copy the bits of the member function pointer, \p mfp, into the member
74	  // function pointer, `entry`.  The kernel launcher will use this to convert
75	  // from host-side to device-side.
76	  template <typename MFP>
77	  void setEntry(const MFP &mfp) {
78	    memcpy(&entry, &mfp, sizeof(EntryType));
79	  }
80	
81	  // This will provide a hook value for the runtime to determine which kernel
82	  // was captured in the C++ host code.
83	  void *getEntry() override { return static_cast<void *>(&entry); }
84	
85	  // We keep a (member) function pointer (specialized by the callable) in order
86	  // to convert from the host-side to the device-side address space.
87	  EntryType entry;
88	
89	  // The actual callable to dispatch upon.
