664	// Control the given cudaq kernel on the given control qubit
665	template <typename QuantumKernel, typename... Args>
666	  requires isCallableVoidKernel<QuantumKernel, Args...>
667	void control(QuantumKernel &&kernel, qubit &control, Args &&...args) {
668	  std::vector<std::size_t> ctrls{control.id()};
669	  getExecutionManager()->startCtrlRegion(ctrls);
670	  kernel(std::forward<Args>(args)...);
671	  getExecutionManager()->endCtrlRegion(ctrls.size());
